-- Catalogue de DÉMONSTRATION Deal Lomé — généré automatiquement.
-- Idempotent et non destructif : conserve les vendeurs démo (des
-- commandes peuvent les référencer) et remplace uniquement leurs produits.
-- Retrait au lancement : DELETE FROM users WHERE firebase_uid LIKE 'demo-seller-%';
BEGIN;
DELETE FROM products WHERE seller_id IN (SELECT sp.id FROM seller_profiles sp JOIN users u ON u.id = sp.user_id WHERE u.firebase_uid LIKE 'demo-seller-%');
COMMIT;
